/**
 * Shape of `public/pqc-benchmarks/pqc-latest.json`. Generated by
 * `apps/web/scripts/run-pqc-benchmarks.ts` and committed to the repo so that
 * any reader can run the same script locally and verify the published numbers
 * match what their hardware produces.
 *
 * Schema v3 (2026-05-14):
 *   - Batched memory measurement (RSS over N=200 instances ÷ N for stability)
 *   - Multi-process concurrency (child_process.fork × 1/2/4/8 — real multi-core)
 *   - Noble comparison (@noble/post-quantum side-by-side native-vs-pure-JS)
 *
 * Schema v2 → v3 iteration: v2's single-instance memory measurement was at
 * noise floor; v3 batches to get reliable per-instance numbers. v2 in-process
 * concurrency saturates on a single Node process; v3 adds child-process scaling
 * to show true multi-core throughput. v2 had no noble comparison; v3 surfaces
 * the native-vs-pure-JS delta on the same hardware.
 *
 * Schema v1 captured only steady-state percentile timings.
 */
export interface PqcBenchmarkSuite {
	readonly schemaVersion: 3;
	readonly generatedAt: string;
	readonly gitSha: string | null;
	readonly liboqsVersion: string;
	readonly nobleVersion: string;
	readonly environment: BenchmarkEnvironment;
	readonly reproducibility: BenchmarkReproducibility;
	readonly kems: readonly KemBenchmark[];
	readonly signatures: readonly SignatureBenchmark[];
}

export interface BenchmarkEnvironment {
	readonly platform: string;
	readonly arch: string;
	readonly cpuModel: string;
	readonly cpuCount: number;
	readonly nodeVersion: string;
	readonly totalMemoryGiB: number;
}

export interface BenchmarkReproducibility {
	readonly publishedJson: string;
	readonly publicMirror: string;
	readonly publicLibrary: string;
	readonly liveSandbox: string;
	readonly readerSnippet: string;
	readonly note: string;
}

export interface KemBenchmark {
	readonly algorithm: string;
	readonly fipsStandard: string;
	readonly securityCategory: number;
	readonly publicKeyBytes: number;
	readonly secretKeyBytes: number;
	readonly ciphertextBytes: number;
	readonly sharedSecretBytes: number;
	readonly iterations: number;
	readonly operations: readonly OperationMeasurement[];
	readonly coldStart: ColdStartMeasurement;
	readonly memoryFootprint: MemoryFootprint;
	readonly concurrency: readonly ConcurrencyMeasurement[];
	readonly multiProcessConcurrency: readonly MultiProcessConcurrencyMeasurement[];
	readonly nobleComparison: NobleComparison | null;
}

export interface SignatureBenchmark {
	readonly algorithm: string;
	readonly fipsStandard: string;
	readonly securityCategory: number;
	readonly publicKeyBytes: number;
	readonly secretKeyBytes: number;
	readonly signatureBytes: number;
	readonly messageBytes: number;
	readonly iterations: number;
	readonly operations: readonly OperationMeasurement[];
	readonly coldStart: ColdStartMeasurement;
	readonly memoryFootprint: MemoryFootprint;
	readonly concurrency: readonly ConcurrencyMeasurement[];
	readonly multiProcessConcurrency: readonly MultiProcessConcurrencyMeasurement[];
	readonly nobleComparison: NobleComparison | null;
}

export interface OperationMeasurement {
	readonly operation: "keygen" | "encaps" | "decaps" | "sign" | "verify";
	readonly p50Ms: number;
	readonly p95Ms: number;
	readonly p99Ms: number;
	readonly meanMs: number;
	readonly opsPerSecond: number;
}

export interface ColdStartMeasurement {
	readonly operation: "keygen";
	readonly firstNMs: readonly number[];
	readonly firstCallMs: number;
	readonly warmupMedianMs: number;
	readonly coldToWarmRatio: number;
}

/**
 * Batched memory footprint. N=200 instances created in a loop; RSS delta
 * divided by N produces a reliable per-instance figure. Single-instance
 * measurement (v2) sat at the OS-page noise floor and was unreliable.
 */
export interface MemoryFootprint {
	readonly batchSize: number;
	readonly baselineRssBytes: number;
	readonly postBatchRssBytes: number;
	readonly perInstanceRssBytes: number;
	readonly v8HeapDeltaBytes: number;
	readonly perInstanceHeapBytes: number;
}

/**
 * In-process concurrency: Promise.all over workers ∈ {1, 2, 4, 8, 16}.
 * liboqs native calls are synchronous; this saturates at single-process
 * throughput. Multi-process measurement (below) is the better scaling signal.
 */
export interface ConcurrencyMeasurement {
	readonly workers: number;
	readonly operation: "keygen";
	readonly totalOps: number;
	readonly durationMs: number;
	readonly opsPerSecond: number;
	readonly scalingEfficiency: number;
}

/**
 * Multi-process concurrency: child_process.fork × N processes.
 * Each child performs OPS_PER_CHILD keygens. Parent aggregates wall-clock
 * across all completions. This is the measurement that reflects real
 * multi-core throughput on a production deployment.
 */
export interface MultiProcessConcurrencyMeasurement {
	readonly processes: number;
	readonly operation: "keygen";
	readonly opsPerProcess: number;
	readonly totalOps: number;
	readonly durationMs: number;
	readonly opsPerSecond: number;
	readonly scalingEfficiency: number;
}

/**
 * Side-by-side comparison: same operation, same iterations, on the same
 * hardware, executed by @cuilabs/liboqs-native (native C) vs @noble/post-quantum
 * (pure JavaScript). The ratio quantifies the native-vs-pure-JS performance
 * delta — a concrete number for "how much slower is the browser SDK".
 *
 * `null` when noble doesn't support the algorithm (e.g., SLH-DSA-SHA2-256f
 * isn't in noble's catalog the same way as ML-KEM).
 */
export interface NobleComparison {
	readonly liboqsKeygenP50Ms: number;
	readonly nobleKeygenP50Ms: number;
	readonly liboqsKeygenOpsPerSecond: number;
	readonly nobleKeygenOpsPerSecond: number;
	readonly speedupRatio: number;
	readonly note?: string;
}
